import React, {useState} from 'react';

const Hobbies = ({config}) => {
    const Swimming = '';
    if(config.image)
    {
        if(config.iconURL === "swimming")
        {
            import ('../resources/swimming.png').then((Swimming)=>{
                console.log("image loaded")
            })
        }
        if(config.iconURL === "electronic_music")
        {
            import ('../resources/Electronic_Music.png').then((ElectronicMusic)=>{
                console.log("image loaded")
            })
        }

    }
    const [isShown, SetShown] = useState(false);
    const [isToggled,SetToggle] = useState('down');
    const handleClick=(element)=>{
        if(element)
            SetToggle('down');
        else
            SetToggle("up");
        SetShown(element);
    };
    return(
        <div>
            <div className={`ui center ${config.segmentColor} segment`}
                 onMouseEnter={() => handleClick(true)}
                 onMouseLeave={() => handleClick(false)}
                 onClick={()=>handleClick(false)}
            >
                <h3>
                    {!config.image && (
                        <i className={`${config.icon} icon`}></i>
                    )
                    }
                    {config.image && config.iconURL === "swimming" && (
                        config.ImageICON
                    )

                    }


                    {config.hobby}
                    {isShown && (
                        <i className={`angle ${isToggled} icon`}></i>
                    )
                    }
                    {!isShown && (
                        <i className={`angle down icon`}></i>
                    )
                    }
                </h3>
                {isShown && (
                    <div className="ui center"><p>{config.content}</p></div>
                )}
            </div>

        </div>
    )
};

export default Hobbies;
